import React, { useState, useEffect, useRef } from 'react';
import { ArrowRight, Play, Square, Loader2 } from 'lucide-react';

interface HeroProps {
  onBookDemoClick?: () => void;
}

const Hero: React.FC<HeroProps> = ({ onBookDemoClick }) => {
  const [scrollY, setScrollY] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    let ticking = false;
    const handleScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          ticking = false;
        });
        ticking = true;
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    
    return () => {
      window.removeEventListener('scroll', handleScroll);
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  const toggleAudio = () => {
    // If audio doesn't exist yet, create it
    if (!audioRef.current) {
      setIsLoading(true);
      const audio = new Audio('data:audio/mpeg;base64,');
      audioRef.current = audio;
      
      audio.oncanplaythrough = () => {
        setIsLoading(false);
        audio.play().catch(err => {
          console.error("Playback blocked by browser:", err);
          setIsPlaying(false);
          setIsLoading(false);
        });
        setIsPlaying(true);
      };

      audio.onended = () => {
        setIsPlaying(false);
      };

      audio.onerror = () => {
        setIsLoading(false);
        setIsPlaying(false);
        console.error("Audio playback error");
      };

      return;
    }

    // Toggle play/pause
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play().catch(err => {
        console.error("Playback error:", err);
        setIsPlaying(false);
      });
      setIsPlaying(true);
    }
  };

  // Generate background particles
  const particles = Array.from({ length: 12 }).map((_, i) => ({
    id: i,
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100 + 10}%`,
    size: `${Math.random() * 2 + 1}px`,
    duration: `${Math.random() * 10 + 10}s`,
    delay: `${Math.random() * 5}s`,
    opacity: Math.random() * 0.3 + 0.1
  }));

  return (
    <section className="relative pt-20 pb-32 px-6 overflow-hidden">
      {/* Animated Background Orbs */}
      <div className="absolute inset-0 pointer-events-none -z-10">
        <div 
          className="absolute top-[10%] left-[5%] w-[400px] h-[400px] bg-blue-600/10 blur-[100px] animate-fluid"
          style={{ transform: `translateY(${scrollY * 0.15}px)` }}
        ></div>
        <div 
          className="absolute bottom-[20%] right-[10%] w-[350px] h-[350px] bg-purple-600/10 blur-[100px] animate-fluid" 
          style={{ 
            animationDelay: '-5s',
            transform: `translateY(${scrollY * 0.08}px)`
          }}
        ></div>
        
        {particles.map((p, i) => (
          <div
            key={p.id}
            className="particle"
            style={{
              left: p.left,
              bottom: '-5%',
              width: p.size,
              height: p.size,
              animationDuration: p.duration,
              animationDelay: p.delay,
              opacity: p.opacity,
              backgroundColor: i % 2 === 0 ? '#4f80ff' : '#9d59ff'
            }}
          />
        ))}
      </div>

      <div className="max-w-7xl mx-auto grid lg:grid-cols-2 gap-12 items-center">
        {/* Left Content */}
        <div className="z-10">
          <div className="inline-flex items-center px-4 py-1.5 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-xs font-bold uppercase tracking-widest mb-8">
            The AI Receptionist for SMBs
          </div>
          
          <h1 className="text-5xl md:text-7xl font-extrabold leading-[1.1] mb-8">
            Never Miss a <br />
            Client <span className="gradient-text">Call</span> Again
          </h1>

          <p className="text-xl text-gray-400 max-w-lg mb-12 leading-relaxed">
            Automatically book appointments, answer FAQs, and capture leads 24/7. 
            Reduce overhead and grow your business with a professional AI receptionist.
          </p>

          <div className="flex flex-col sm:flex-row items-center gap-6">
            <button 
              onClick={onBookDemoClick}
              className="w-full sm:w-auto gradient-btn px-8 py-4 rounded-full font-bold flex items-center justify-center gap-2 hover:opacity-90 transition-all shadow-lg"
            >
              Book a Demo <ArrowRight size={20} />
            </button>
            
            <div className="flex items-center gap-4 w-full sm:w-auto">
              <button 
                onClick={toggleAudio}
                disabled={isLoading}
                className={`w-full sm:w-auto px-8 py-4 rounded-full border border-white/10 glass font-bold flex items-center justify-center gap-2 transition-all group relative overflow-hidden ${isPlaying ? 'bg-blue-500/10 border-blue-500/50 shadow-[0_0_20px_rgba(59,130,246,0.3)]' : 'hover:bg-white/10'}`}
              >
                {isLoading ? (
                  <>
                    <Loader2 size={18} className="animate-spin text-blue-400" /> Loading Demo...
                  </>
                ) : isPlaying ? (
                  <>
                    <Square size={16} fill="white" className="animate-pulse" /> Stop Demo
                  </>
                ) : (
                  <>
                    <Play size={18} fill="currentColor" className="group-hover:scale-110 transition-transform" /> Hear a Live Demo
                  </>
                )}
              </button>

              {/* Waveform Visualizer */}
              {isPlaying && (
                <div className="hidden md:flex items-end gap-1 h-8 px-2 animate-in fade-in duration-500">
                  {[...Array(12)].map((_, i) => (
                    <div 
                      key={i} 
                      className="w-1 bg-blue-400 rounded-full animate-audio-wave" 
                      style={{ 
                        animationDelay: `${i * 0.1}s`,
                        animationDuration: `${0.6 + Math.random() * 0.4}s`
                      }}
                    ></div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Content - Visual Mockups */}
        <div className="relative h-[400px] lg:h-[500px] flex flex-col justify-center">
          <div 
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] h-[300px] bg-blue-500/10 blur-[80px] rounded-full -z-10"
            style={{ transform: `translate(-50%, calc(-50% + ${scrollY * 0.1}px))` }}
          ></div>
          
          <div className="relative space-y-6 w-full">
            {/* Caller Card */}
            <div 
              className="glass p-6 rounded-2xl w-full max-w-[320px] ml-auto relative overflow-hidden hovering-card custom-shadow border-white/20"
              style={{ transform: `translateY(${scrollY * -0.05}px)` }}
            >
              <div className="absolute top-0 left-0 w-1 h-full bg-cyan-400"></div>
              <div className="flex items-center gap-2 mb-3">
                <div className="w-2 h-2 rounded-full bg-cyan-400"></div>
                <span className="text-[10px] font-bold uppercase tracking-widest text-cyan-400">Caller: William Smith</span>
              </div>
              <p className="text-gray-200 text-sm font-medium italic">"Hi, I'm a new patient. Can I book an appointment for this week?"</p>
            </div>

            {/* AI Confirmation Card */}
            <div 
              className="glass p-6 rounded-2xl w-full max-w-[320px] mr-auto relative overflow-hidden hovering-card custom-shadow border-white/20" 
              style={{ 
                animationDelay: '-2s',
                transform: `translateY(${scrollY * -0.03}px)`
              }}
            >
              <div className="absolute top-0 left-0 w-1 h-full bg-purple-500"></div>
              <div className="flex items-center gap-2 mb-3">
                <div className="w-2 h-2 rounded-full bg-purple-500"></div>
                <span className="text-[10px] font-bold uppercase tracking-widest text-purple-400">AI Confirmed: Beth</span>
              </div>
              <p className="text-gray-200 text-sm font-medium italic">"Got it, William. Your appointment for Tuesday at 10 AM is all set!"</p>
            </div>
          </div>
          
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[140%] h-[140%] pointer-events-none -z-20">
            <div className="absolute inset-0 border border-blue-500/5 rounded-full animate-pulse"></div>
            <div className="absolute inset-[10%] border border-purple-500/5 rounded-full animate-[pulse_5s_linear_infinite]"></div>
          </div>
        </div>
      </div>
      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes audio-wave {
          0%, 100% { height: 20%; }
          50% { height: 100%; }
        }
        .animate-audio-wave {
          animation: audio-wave 1s ease-in-out infinite;
        }
      `}} />
    </section>
  );
};

export default Hero;

